from __future__ import annotations

from urllib.parse import quote_plus, urlparse


SEARCH_URL = "https://duckduckgo.com/?q={}"


def address_to_uri(value: str, search_url: str = SEARCH_URL) -> str:
    """Turn address-bar input into either a URL or a DuckDuckGo search."""
    value = value.strip()
    if not value:
        return "trowser://homepage"
    if value.startswith("trowser://"):
        return value
    parsed = urlparse(value)
    if parsed.scheme in {"http", "https", "file", "about"}:
        return value
    if " " not in value and ("." in value or value.startswith("localhost")):
        return f"http://{value}"
    return search_url.format(quote_plus(value))


def display_uri(uri: str | None) -> str:
    if not uri or uri == "trowser://homepage":
        return ""
    return uri
